// staged files → Guardian → exit 1 on critical; --bypass logs reason

import { Guardian, MockReplacementPlugin, PhantomDependencyPlugin, SecretDetectionPlugin } from "@snapback/core";
import { execSync } from "node:child_process";
import { existsSync, readFileSync } from "node:fs";

interface CheckOptions {
	staged?: boolean;
	bypass?: string;
}

export async function check(options: CheckOptions = {}): Promise<number> {
	try {
		// Get staged files if requested
		let filesToCheck: string[] = [];
		if (options.staged) {
			filesToCheck = getStagedFiles();
		} else {
			// For now, we'll just return success if not checking staged files
			console.log("No files to check");
			return 0;
		}

		if (filesToCheck.length === 0) {
			console.log("No staged files to check");
			return 0;
		}

		// Initialize Guardian with plugins
		const guardian = new Guardian();
		guardian.addPlugin(new SecretDetectionPlugin());
		guardian.addPlugin(new MockReplacementPlugin());
		guardian.addPlugin(new PhantomDependencyPlugin());

		// Run Guardian analysis on the files
		const findings = await analyzeFiles(filesToCheck, guardian);

		// Log findings
		if (findings.length > 0) {
			console.log("Guardian findings:");
			for (const finding of findings) {
				console.log(`  ${finding.file}:${finding.line} [${finding.severity}] ${finding.message}`);
			}

			// Check for critical findings (risk > 8)
			const criticalFindings = findings.filter((f) => f.risk > 8);
			if (criticalFindings.length > 0) {
				if (options.bypass) {
					console.log(`⚠️  Critical findings bypassed: ${options.bypass}`);
					// Log audit entry for bypass
					logAudit("check_bypassed", {
						bypassReason: options.bypass,
						criticalFindings: criticalFindings.length,
					});
					return 0;
				}
				console.error("❌ Critical findings detected. Commit blocked.");
				// Log audit entry for block
				logAudit("check_blocked", {
					criticalFindings: criticalFindings.length,
				});
				return 1;
			}
		} else {
			console.log("✅ No findings detected");
		}

		return 0;
	} catch (error) {
		console.error("Error during check:", error);
		// Log audit entry for error
		logAudit("check_error", {
			error: error instanceof Error ? error.message : String(error),
		});
		return 1;
	}
}

function getStagedFiles(): string[] {
	try {
		const output = execSync("git diff --cached --name-only", { encoding: "utf-8" });
		return output.split("\n").filter(Boolean);
	} catch (error) {
		console.error("Failed to get staged files:", error);
		return [];
	}
}

async function analyzeFiles(files: string[], guardian: Guardian): Promise<GuardianFinding[]> {
	const findings: GuardianFinding[] = [];

	for (const file of files) {
		try {
			if (existsSync(file)) {
				const content = readFileSync(file, "utf-8");

				// Analyze with Guardian
				const result = await guardian.analyze(content, file);

				// Convert Guardian result to findings
				if (result.score > 0) {
					findings.push({
						file,
						line: 1,
						risk: result.score,
						severity: result.severity || "medium",
						message: result.factors.join(", "),
						suggestions: result.recommendations,
					});
				}
			}
		} catch (error) {
			console.warn(`Failed to analyze file ${file}:`, error);
		}
	}

	return findings;
}

interface GuardianFinding {
	file: string;
	line: number;
	risk: number;
	severity: string;
	message: string;
	suggestions?: string[];
}

function logAudit(action: string, details: Record<string, any>): void {
	// Simple audit logging to console for now
	console.log(`[AUDIT] ${new Date().toISOString()} ${action}:`, JSON.stringify(details));
}

// CLI entry point
if (require.main === module) {
	const args = process.argv.slice(2);
	const options: CheckOptions = {};

	for (let i = 0; i < args.length; i++) {
		if (args[i] === "--staged") {
			options.staged = true;
		} else if (args[i] === "--bypass" && i + 1 < args.length) {
			options.bypass = args[++i];
		}
	}

	check(options)
		.then((exitCode) => {
			process.exit(exitCode);
		})
		.catch((error) => {
			console.error("Unexpected error:", error);
			process.exit(1);
		});
}

