// Import the mock auth service
import { authenticate as mockAuthenticate } from "@snapback/auth-mock";
import { logger } from "@snapback/infrastructure";

// In-memory cache for authentication results
// Key: API key, Value: { timestamp, result }
const authCache = new Map<string, { timestamp: number; result: AuthResult }>();

// Cache duration: 1 minute (60,000 milliseconds)
const CACHE_DURATION = 60 * 1000;

interface AuthResult {
	valid: boolean;
	tier: "free" | "pro";
	scopes?: string[];
	error?: string;
}

/**
 * Authenticate an API key and return the user's tier and scopes
 * Uses a 1-minute cache to reduce backend calls
 *
 * @param apiKey - The API key to authenticate
 * @returns Authentication result with validity, tier, and scopes
 */
export async function authenticate(apiKey: string): Promise<AuthResult> {
	const now = Date.now();

	// Check cache first
	const cached = authCache.get(apiKey);
	if (cached && now - cached.timestamp < CACHE_DURATION) {
		logger.debug("Using cached auth result", {
			apiKey: `${apiKey.substring(0, 8)}...`,
			timestamp: cached.timestamp,
		});
		return cached.result;
	}

	// Perform actual authentication
	const result = await performAuth(apiKey);

	// Cache the result
	authCache.set(apiKey, {
		timestamp: now,
		result,
	});

	// Clean up old cache entries periodically
	if (authCache.size > 1000) {
		// Prevent unbounded cache growth
		cleanupCache(now);
	}

	return result;
}

/**
 * Perform the actual authentication logic
 * In a real implementation, this would call the backend service
 * For now, we'll implement the mock logic as specified in AU1-A
 *
 * @param apiKey - The API key to authenticate
 * @returns Authentication result
 */
async function performAuth(apiKey: string): Promise<AuthResult> {
	// Check if we're in no_network mode (for testing)
	const noNetwork = process.env.SNAPBACK_NO_NETWORK === "true";

	if (noNetwork) {
		// Use the mock auth service
		return await mockAuthenticate(apiKey);
	}

	// Check if we have a backend URL configured
	const backendUrl = process.env.SNAPBACK_BACKEND_URL;

	if (backendUrl) {
		// In a real implementation with network access:
		// This would make an HTTP request to the backend service
		logger.warn("Network authentication not implemented, using mock", {
			apiKey: `${apiKey.substring(0, 8)}...`,
			backendUrl,
		});
	}

	// Use mock authentication based on key format
	if (!apiKey) {
		return {
			valid: true,
			tier: "free",
			scopes: [],
		};
	}

	if (apiKey.startsWith("sb_live_")) {
		return {
			valid: true,
			tier: "pro",
			scopes: ["analyze", "checkpoint", "context"],
		};
	}

	return {
		valid: false,
		tier: "free",
		error: "Invalid API key format",
	};
}

/**
 * Clean up old entries from the authentication cache
 *
 * @param now - Current timestamp
 */
function cleanupCache(now: number): void {
	for (const [key, value] of authCache.entries()) {
		if (now - value.timestamp >= CACHE_DURATION) {
			authCache.delete(key);
		}
	}
}

/**
 * Clear the authentication cache (useful for testing)
 */
export function clearAuthCache(): void {
	authCache.clear();
}

