// Token bucket rate limiting implementation
interface TokenBucket {
	tokens: number;
	lastRefill: number;
	capacity: number;
	refillRate: number; // tokens per millisecond
}

// In-memory store for token buckets (in a real implementation, this would use Redis or similar)
const buckets = new Map<string, TokenBucket>();

// Default rate limit configuration
const DEFAULT_CAPACITY = 100; // Maximum tokens
const DEFAULT_REFILL_RATE = 100 / (60 * 1000); // 100 tokens per minute (tokens per millisecond)

/**
 * Initialize or get a token bucket for a key
 * @param key The key to get/create a bucket for
 * @param capacity Maximum tokens in the bucket
 * @param refillRate Tokens added per millisecond
 * @returns The token bucket
 */
function getBucket(
	key: string,
	capacity: number = DEFAULT_CAPACITY,
	refillRate: number = DEFAULT_REFILL_RATE,
): TokenBucket {
	const now = Date.now();

	if (!buckets.has(key)) {
		// Create a new bucket
		buckets.set(key, {
			tokens: capacity,
			lastRefill: now,
			capacity,
			refillRate,
		});
	}

	const bucket = buckets.get(key);
	if (!bucket) {
		throw new Error(`Bucket not found for key: ${key}`);
	}

	// Refill tokens based on time passed
	const timePassed = now - bucket.lastRefill;
	const tokensToAdd = timePassed * refillRate;

	if (tokensToAdd > 0) {
		bucket.tokens = Math.min(bucket.capacity, bucket.tokens + tokensToAdd);
		bucket.lastRefill = now;
	}

	return bucket;
}

/**
 * Try to consume tokens from a bucket
 * @param key The key to consume tokens for
 * @param tokens Number of tokens to consume (default: 1)
 * @param capacity Maximum tokens in the bucket
 * @param refillRate Tokens added per millisecond
 * @returns True if tokens were consumed, false if rate limited
 */
export function consumeTokens(key: string, tokens = 1, capacity?: number, refillRate?: number): boolean {
	const bucket = getBucket(key, capacity, refillRate);

	if (bucket.tokens >= tokens) {
		bucket.tokens -= tokens;
		return true; // Successfully consumed tokens
	}

	return false; // Rate limited
}

/**
 * Check if a key is rate limited without consuming tokens
 * @param key The key to check
 * @param tokens Number of tokens to check for (default: 1)
 * @param capacity Maximum tokens in the bucket
 * @param refillRate Tokens added per millisecond
 * @returns True if rate limited, false if tokens are available
 */
export function isRateLimited(key: string, tokens = 1, capacity?: number, refillRate?: number): boolean {
	const bucket = getBucket(key, capacity, refillRate);
	return bucket.tokens < tokens;
}

/**
 * Get rate limit info for a key
 * @param key The key to get info for
 * @param capacity Maximum tokens in the bucket
 * @param refillRate Tokens added per millisecond
 * @returns Rate limit information
 */
export function getRateLimitInfo(
	key: string,
	capacity?: number,
	refillRate?: number,
): {
	remaining: number;
	capacity: number;
	resetTime: number;
	isRateLimited: boolean;
} {
	const bucket = getBucket(key, capacity, refillRate);
	const tokensNeeded = 1; // For next request
	const isLimited = bucket.tokens < tokensNeeded;

	// Calculate when the bucket will have enough tokens
	let resetTime = 0;
	if (isLimited && bucket.refillRate > 0) {
		const tokensRequired = tokensNeeded - bucket.tokens;
		const timeUntilReset = tokensRequired / bucket.refillRate;
		resetTime = Date.now() + timeUntilReset;
	}

	return {
		remaining: Math.max(0, Math.floor(bucket.tokens)),
		capacity: bucket.capacity,
		resetTime,
		isRateLimited: isLimited,
	};
}

/**
 * Clear all buckets (useful for testing)
 */
export function clearBuckets(): void {
	buckets.clear();
}

/**
 * Clear a specific bucket (useful for testing)
 * @param key The key to clear
 */
export function clearBucket(key: string): void {
	buckets.delete(key);
}

