import { z } from "zod";
import { generateSnapshotHash } from "../utils/blake3.js";

// Schema for create snapshot tool
export const CreateSnapshotSchema = z.object({
	filePath: z.string().optional().describe("Optional file path to create snapshot for"),
	reason: z.string().optional().describe("Optional reason for creating the snapshot"),
	content: z.string().optional().describe("Optional content to snapshot"),
	files: z
		.array(
			z.object({
				path: z.string().describe("File path"),
				content: z.string().describe("File content"),
			}),
		)
		.optional()
		.describe("Array of files to snapshot"),
});

/**
 * Create a snapshot with content-addressed ID
 *
 * @param input - The input parameters for creating a snapshot
 * @returns The snapshot ID and metadata
 */
export async function createSnapshot(input: z.infer<typeof CreateSnapshotSchema>) {
	try {
		// Generate snapshot ID using Blake3 hash
		let snapshotId: string;

		if (input.files && input.files.length > 0) {
			// Generate hash from files
			snapshotId = generateSnapshotHash(input.files);
		} else if (input.content) {
			// Generate hash from content
			snapshotId = generateSnapshotHash([{ path: "content", content: input.content }]);
		} else {
			// Generate hash from timestamp if no content provided
			snapshotId = generateSnapshotHash([{ path: "timestamp", content: Date.now().toString() }]);
		}

		// Prefix with snap- to match expected format
		const formattedSnapshotId = `snap-${snapshotId.substring(0, 16)}`;

		// Create snapshot metadata
		const snapshot = {
			id: formattedSnapshotId,
			timestamp: Date.now(),
			reason: input.reason || "MCP snapshot",
			filePath: input.filePath,
			fileCount: input.files ? input.files.length : input.content ? 1 : 0,
		};

		return {
			success: true,
			snapshot,
		};
	} catch (error) {
		return {
			success: false,
			error: error instanceof Error ? error.message : "Unknown error",
		};
	}
}

