const snapshots: Array<{
	id: string;
	timestamp: number;
	reason: string;
	filePath?: string;
	fileCount: number;
}> = [];

/**
 * List all snapshots
 *
 * @returns Array of snapshots sorted by timestamp (newest first)
 */
export async function listSnapshots() {
	try {
		// Return snapshots sorted by timestamp (newest first)
		const sortedSnapshots = [...snapshots].sort((a, b) => b.timestamp - a.timestamp);

		return {
			success: true,
			snapshots: sortedSnapshots,
		};
	} catch (error) {
		return {
			success: false,
			error: error instanceof Error ? error.message : "Unknown error",
		};
	}
}

