import { listSnapshots } from "./list-snapshots.js";

// In-memory storage for snapshot contents (in a real implementation, this would be persistent storage)
const snapshotContents: Map<string, Array<{ path: string; content: string }>> = new Map();

/**
 * Restore a snapshot by ID
 *
 * @param snapshotId - The ID of the snapshot to restore
 * @returns The restored snapshot content
 */
export async function restoreSnapshot(snapshotId: string) {
	try {
		// Check if snapshot exists
		const snapshotList = await listSnapshots();
		if (!snapshotList.success) {
			return {
				success: false,
				error: "Failed to retrieve snapshot list",
			};
		}

		// Check if snapshots array exists
		if (!snapshotList.snapshots) {
			return {
				success: false,
				error: "No snapshots found",
			};
		}

		const snapshot = snapshotList.snapshots.find((s) => s.id === snapshotId);
		if (!snapshot) {
			return {
				success: false,
				error: `Snapshot with ID ${snapshotId} not found`,
			};
		}

		// Get snapshot content
		const content = snapshotContents.get(snapshotId);
		if (!content) {
			return {
				success: false,
				error: `Snapshot content for ID ${snapshotId} not found`,
			};
		}

		return {
			success: true,
			snapshot: {
				id: snapshot.id,
				timestamp: snapshot.timestamp,
				reason: snapshot.reason,
				filePath: snapshot.filePath,
				fileCount: snapshot.fileCount,
				content,
			},
		};
	} catch (error) {
		return {
			success: false,
			error: error instanceof Error ? error.message : "Unknown error",
		};
	}
}

/**
 * Store snapshot content
 *
 * @param snapshotId - The ID of the snapshot
 * @param content - The content to store
 */
export function storeSnapshotContent(snapshotId: string, content: Array<{ path: string; content: string }>) {
	snapshotContents.set(snapshotId, content);
}

